window.COURSE_LANG = window.COURSE_LANG || {};
window.COURSE_LANG["electrology"] = window.COURSE_LANG["electrology"] || {};
window.COURSE_LANG["electrology"]["es"] = [
  {"id":1,"q":"La aguja (sonda) que se introduce en un folículo piloso debe ser:","opts":["Limpiada con alcohol y reutilizada en el siguiente cliente","Desinfectada con una toallita y reutilizada todo el día","Enjuagada bajo agua corriente entre clientes","Estéril y usada en un solo cliente"],"re":"Una sonda que penetra la piel debe ser estéril; las sondas desechables de un solo uso son lo habitual para no reutilizarlas en otro cliente."},
  {"id":2,"q":"¿Qué dispositivo es aceptable para esterilizar instrumentos metálicos reutilizables en electrología?","opts":["Un autoclave o un esterilizador de calor seco","Una caja de almacenamiento con luz UV","Un esterilizador de perlas de vidrio","Un recipiente con desinfectante"],"re":"La verdadera esterilización requiere un autoclave (vapor a presión) o un esterilizador de calor seco; las cajas UV y los de perlas no esterilizan de forma fiable."},
  {"id":3,"q":"La esterilización se diferencia de la desinfección porque la esterilización:","opts":["Solo quita la suciedad visible","Funciona solo sobre la piel","Solo reduce el número de gérmenes","Destruye toda forma de vida microbiana, incluidas las esporas bacterianas"],"re":"La esterilización destruye todos los microorganismos, incluidas las esporas resistentes, mientras que la desinfección solo elimina la mayoría de los patógenos de una superficie."},
  {"id":4,"q":"Antes de poder desinfectar o esterilizar cualquier instrumento, primero hay que:","opts":["Limpiarlo para quitar los residuos visibles","Ponerlo en una caja UV","Secarlo al sol","Envolverlo en una toalla"],"re":"La limpieza para retirar sangre y residuos debe ir primero, porque la materia orgánica impide que el desinfectante y la esterilización lleguen a la superficie."},
  {"id":5,"q":"Una sonda desechable usada debe desecharse en:","opts":["Un bote de basura común","Un contenedor de reciclaje","Un contenedor para objetos punzantes resistente a perforaciones","Una bolsa de papel en la estación"],"re":"Las agujas y sondas usadas son objetos punzocortantes y deben ir a un contenedor para punzantes etiquetado, hermético y resistente a perforaciones, como residuo médico."},
  {"id":6,"q":"Durante un tratamiento, el electrólogo debe usar:","opts":["Sin guantes, para sentir mejor","Guantes de tela lavados una vez por semana","Guantes de examen desechables nuevos","Guantes solo si aparece sangre"],"re":"Se usa un par de guantes de examen desechables nuevos (látex, nitrilo o vinilo) con cada cliente para protegerse del contacto con sangre y fluidos corporales."},
  {"id":7,"q":"Las manos deben lavarse:","opts":["Solo al inicio del día","Solo cuando se ven sucias","Una vez en el almuerzo","Antes y después de cada cliente"],"re":"Lavarse las manos antes y después de cada cliente es una medida básica de control de infecciones que limita la propagación de microorganismos."},
  {"id":8,"q":"Los instrumentos reutilizables esterilizados que no están en uso deben guardarse:","opts":["En un recipiente limpio y cubierto","Sueltos en un cajón con otras herramientas","Sobre una toalla abierta en la estación","En el bolsillo de una bata"],"re":"Tras la esterilización, los instrumentos reutilizables como las pinzas se guardan en un recipiente limpio y cubierto para que sigan protegidos de la contaminación."},
  {"id":9,"q":"Bajo las precauciones estándar (universales), el electrólogo trata:","opts":["Solo la sangre de clientes que se ven enfermos como peligro","Solo su propia sangre como riesgo","Una pequeña cantidad de sangre como inofensiva","Toda sangre y fluido corporal humano como potencialmente infeccioso"],"re":"Las precauciones estándar implican tratar la sangre y los fluidos de cada cliente como si pudieran portar un patógeno sanguíneo como VHB, VHC o VIH."},
  {"id":10,"q":"Las tres fases del ciclo de crecimiento del pelo son:","opts":["Anágena, catágena, telógena","Primaria, secundaria, terciaria","Inicio, medio, fin","Activa, en pausa, removida"],"re":"El pelo pasa por anágena (crecimiento activo), catágena (transición) y telógena (reposo)."},
  {"id":11,"q":"La electrólisis es más eficaz en un pelo que está en fase:","opts":["Telógena (reposo)","Catágena (transición)","Anágena (crecimiento activo)","De caída (exógena)"],"re":"En anágena el pelo está firmemente unido a sus células de crecimiento en el fondo del folículo, por lo que destruir esas células es más eficaz durante el crecimiento activo."},
  {"id":12,"q":"El conjunto de células en la base del folículo que aporta sangre y nutrientes para el crecimiento del pelo es:","opts":["El tallo del pelo","El músculo erector del pelo","La papila dérmica","El conducto sebáceo"],"re":"La papila dérmica en la base del bulbo lleva el aporte capilar que nutre al pelo en crecimiento; las células objetivo de la electrólisis se agrupan a su alrededor."},
  {"id":13,"q":"Las células que se dividen activamente y producen el tallo del pelo se encuentran en:","opts":["La matriz del bulbo piloso","La superficie de la epidermis","La glándula sudorípara","El lecho ungueal"],"re":"La matriz rodea la papila dérmica en el bulbo; sus células de rápida división forman el tallo del pelo, por lo que la zona del bulbo es el objetivo del tratamiento."},
  {"id":14,"q":"El pequeño músculo unido al folículo que se contrae y causa la \"piel de gallina\" es:","opts":["La glándula sebácea","La glándula sudorípara","La papila dérmica","El músculo erector del pelo (arrector pili)"],"re":"El erector del pelo es un pequeño músculo liso unido al folículo; al contraerse levanta el pelo y produce la piel de gallina."},
  {"id":15,"q":"La glándula de grasa conectada al folículo piloso es:","opts":["La glándula sebácea","La glándula sudorípara","El ganglio linfático","La glándula sudorípara ecrina"],"re":"La glándula sebácea (de grasa) desemboca en el folículo y secreta sebo; junto con el folículo y el erector forma la unidad pilosebácea."},
  {"id":16,"q":"La parte visible del pelo por encima de la superficie de la piel se llama:","opts":["La raíz del pelo","El bulbo piloso","El tallo del pelo","La papila dérmica"],"re":"El tallo es la porción por encima de la superficie; la raíz y el bulbo quedan debajo de la piel dentro del folículo."},
  {"id":17,"q":"La capa más externa de la piel, que la sonda atraviesa para llegar al folículo, es:","opts":["La dermis","La capa subcutánea","La epidermis","La capa muscular"],"re":"La epidermis es la fina capa externa; el folículo y sus células de crecimiento están más profundos en la dermis, donde la sonda se guía junto al pelo."},
  {"id":18,"q":"En la mayor parte del cuero cabelludo, en un momento dado, la mayoría de los pelos están en:","opts":["Telógena","Catágena","Anágena","Exógena"],"re":"En cualquier momento, la mayoría de los pelos del cuero cabelludo (alrededor del 85-90%) están en fase anágena, con fracciones menores en catágena y telógena."},
  {"id":19,"q":"La electrólisis es reconocida por la FDA de EE. UU. como un método de:","opts":["Solo reducción permanente del vello","Eliminación temporal del vello","Eliminación permanente del vello","Aclarado del vello"],"re":"La FDA reconoce la electrólisis como método de eliminación permanente del vello, mientras que los equipos láser solo están autorizados para reducción permanente."},
  {"id":20,"q":"El método galvánico destruye las células de crecimiento del pelo mediante:","opts":["Producir una sustancia química cáustica (lejía/sosa) en el folículo","Producir calor que cuece el folículo","Arrancar el pelo de raíz","Congelar el folículo"],"re":"El galvánico usa corriente continua para producir hidróxido de sodio (lejía) a partir de la sal y el agua del folículo; la lejía cáustica destruye químicamente las células de crecimiento."},
  {"id":21,"q":"¿Qué tipo de corriente usa el método galvánico?","opts":["Corriente continua (CC)","Corriente alterna de alta frecuencia","Ninguna corriente","Electricidad estática"],"re":"La electrólisis galvánica usa corriente continua, que impulsa la reacción química que forma lejía en el folículo."},
  {"id":22,"q":"La termólisis (onda corta) elimina el pelo mediante:","opts":["Una reacción química que forma lejía","Calor producido por corriente de alta frecuencia","Descomposición por corriente continua","Raspado mecánico"],"re":"La termólisis usa corriente alterna de alta frecuencia que produce calor en el folículo y destruye térmicamente las células de crecimiento."},
  {"id":23,"q":"En comparación con la termólisis, el método galvánico puro suele ser:","opts":["Mucho más rápido por pelo","Incapaz de eliminar el pelo","Exactamente igual de rápido","Más lento por pelo"],"re":"El galvánico depende de una reacción química más lenta y puede tardar minutos por folículo, mientras que la termólisis actúa en segundos; por esa diferencia se creó el método blend."},
  {"id":24,"q":"El método blend (combinado) combina:","opts":["Corrientes galvánica y de termólisis","Dos máquinas de termólisis","Depilación con cera y pinzas","Láser y galvánica"],"re":"El blend aplica a la vez corriente galvánica y de termólisis (alta frecuencia), combinando la producción de lejía con el calor para un tratamiento eficaz."},
  {"id":25,"q":"Una ventaja principal del blend frente al galvánico puro es que es:","opts":["Más barato de comprar","Capaz de prescindir de la sonda","Más rápido por pelo manteniendo la eficacia del galvánico","Totalmente indoloro"],"re":"Añadir calor acelera la acción química de la lejía, por lo que el blend trata cada pelo mucho más rápido que el galvánico puro y sigue siendo muy eficaz."},
  {"id":26,"q":"En la electrólisis galvánica, la lejía cáustica se produce en:","opts":["El electrodo positivo que sostiene el cliente","El electrodo negativo (la aguja en el folículo)","La superficie de la piel","El cable de corriente"],"re":"Con la aguja actuando como electrodo negativo (cátodo), la reacción en ese electrodo forma hidróxido de sodio (lejía) dentro del folículo."},
  {"id":27,"q":"Las tres modalidades de electrólisis comparten el paso básico de:","opts":["Aplicar una crema para disolver el pelo","Usar un haz láser","Rasurar antes la zona","Insertar una sonda fina en el folículo piloso"],"re":"Galvánica, termólisis y blend funcionan guiando una sonda fina por el folículo para llevar corriente a las células de crecimiento de la base."},
  {"id":28,"q":"Tras aplicar la corriente, el pelo aflojado se retira:","opts":["Levantándolo suavemente con pinzas","Tirando fuerte en contra de su dirección de crecimiento","Raspándolo con una hoja","Dejando que se caiga solo días después"],"re":"Un pelo bien tratado sale sin resistencia al levantarlo con pinzas; si tira, las células de crecimiento no se trataron lo suficiente."},
  {"id":29,"q":"Una sonda aislada está diseñada para que la energía se concentre:","opts":["En la superficie de la piel","En la punta, cerca de la base del folículo","A lo largo de todo el cuerpo de la sonda","Fuera del folículo"],"re":"El aislamiento a lo largo del cuerpo de la sonda evita que la energía afecte al folículo superior y la superficie, enfocándola en la punta expuesta cerca de las células de crecimiento."},
  {"id":30,"q":"La sonda debe elegirse de modo que su diámetro:","opts":["Sea mucho mayor que el pelo","No importe en absoluto","Sea siempre el más delgado disponible","Coincida aproximadamente con el diámetro del pelo a tratar"],"re":"Una sonda cercana al diámetro del propio pelo se desliza suavemente por el folículo y entrega la energía con eficacia, sin forzar ni causar molestia extra."},
  {"id":31,"q":"La sonda debe insertarse:","opts":["Recta hacia abajo a través de la piel, lejos del pelo","En ángulo recto respecto al pelo","Suavemente siguiendo el ángulo natural del folículo","Solo hasta la mitad de la epidermis"],"re":"La sonda sigue el ángulo natural del pelo por el folículo para llegar a la base con suavidad sin perforar la pared del folículo."},
  {"id":32,"q":"Si la intensidad de la corriente se ajusta demasiado alta, el resultado probable es:","opts":["El pelo se trata con más suavidad","Daño en la piel, como una quemadura o picaduras","No pasa nada","La sonda dura más"],"re":"Una intensidad excesiva puede sobretratar el tejido y lesionar la piel, causando quemaduras, costras o picaduras; los ajustes se adaptan al pelo y a la piel."},
  {"id":33,"q":"Si la sonda se inserta demasiado superficial, lo probable es que el tratamiento:","opts":["Alcance perfectamente las células de crecimiento","Esterilice la sonda","Sea más cómodo y más eficaz","Falle las células de crecimiento y dañe la piel superior"],"re":"Las células de crecimiento están en la base del folículo; una inserción superficial las omite y concentra la energía cerca de la superficie, con riesgo de dañar la piel."},
  {"id":34,"q":"Una sonda de dos piezas se diferencia de una de una pieza en que suele ser:","opts":["Más flexible","De vidrio","Reutilizable indefinidamente","Magnética"],"re":"Las sondas de dos piezas tienen un cuerpo y un mango separados y tienden a ser más flexibles, mientras que las de una pieza son más rígidas; ambas son de un solo uso y estériles."},
  {"id":35,"q":"Una buena ampliación e iluminación en el área de trabajo son importantes porque:","opts":["Hacen que la sala se vea profesional","Ayudan al electrólogo a seguir el folículo e insertar con precisión","Son necesarias para alimentar el epilador","Sustituyen la necesidad de una sonda"],"re":"La ampliación y la buena luz permiten ver con claridad el ángulo del pelo para inserciones precisas y suaves y resultados constantes."},
  {"id":36,"q":"En el blend, los ajustes de tiempo/intensidad se adaptan principalmente según:","opts":["El color de la sala","La profundidad y el grosor del pelo y la tolerancia del cliente","La hora del día","La marca de las pinzas"],"re":"Los ajustes se adaptan al pelo individual (su profundidad y grosor) y a la comodidad del cliente para destruir las células de crecimiento sin dañar la piel."},
  {"id":37,"q":"La electrólisis está generalmente contraindicada en un cliente que tiene:","opts":["Pelo oscuro y grueso","Ojos marrones","Piel seca","Un marcapasos cardíaco"],"re":"La corriente eléctrica aplicada podría interferir con un marcapasos, por lo que se evita el tratamiento o solo se hace con autorización escrita de un médico."},
  {"id":38,"q":"NO se debe realizar electrólisis sobre una zona que tenga:","opts":["Un brote activo de herpes u otra infección de la piel","Piel normal y sana","Unos pocos pelos finos","Ligera sequedad"],"re":"Tratar sobre una infección activa como el herpes simple puede propagarla y dificulta la cicatrización; hay que esperar a que la zona esté del todo curada."},
  {"id":39,"q":"A un cliente con antecedentes de formar queloides se le debe decir que la electrólisis:","opts":["Curará los queloides","Puede causar cicatrices abultadas y, en general, no se aconseja","No tiene ningún riesgo para él","Elimina las cicatrices existentes"],"re":"Las personas propensas a queloides pueden desarrollar tejido cicatricial abultado por el trauma de la piel, por lo que la electrólisis no suele aconsejarse para ellas."},
  {"id":40,"q":"Antes de tratar el pelo que crece de un lunar, la práctica más segura es:","opts":["Tratarlo sin ninguna preocupación","Cortar el lunar uno mismo","Hacer que un médico evalúe el lunar primero","Negar todo servicio para siempre"],"re":"El pelo de un lunar puede tratarse, pero el lunar debe ser revisado primero por un médico para descartar algo sospechoso antes de trabajar sobre él."},
  {"id":41,"q":"En un cliente con diabetes, el electrólogo debe saber que esa persona:","opts":["Cicatriza más rápido que el promedio","No necesita ninguna consideración especial","No siente la sonda en absoluto, así que use la corriente máxima","Puede cicatrizar más lento y ser propenso a infecciones"],"re":"La diabetes puede retrasar la cicatrización y aumentar el riesgo de infección, así que el tratamiento es suave, las zonas se mantienen pequeñas y suele convenir la opinión de un médico."},
  {"id":42,"q":"El propósito de una consulta previa y un historial de salud del cliente es:","opts":["Vender más productos","Identificar contraindicaciones y planificar un tratamiento seguro","Ajustar la temperatura de la sala","Decidir solo el precio"],"re":"La consulta revela enfermedades, medicamentos y problemas de la piel para que el electrólogo identifique contraindicaciones y trate de forma segura."},
  {"id":43,"q":"Un consejo de cuidado posterior adecuado para un cliente incluye:","opts":["Frotar la zona con fuerza de inmediato","Mantener la zona limpia y no rascarla","Aplicar maquillaje pesado de inmediato","Tomar el sol en la zona tratada enseguida"],"re":"La piel tratada está cicatrizando, así que se aconseja al cliente mantenerla limpia, no tocarla ni rascarla, y protegerla (por ejemplo del sol) mientras se recupera."},
  {"id":44,"q":"Si una clienta informa que está embarazada, el electrólogo debe:","opts":["Aumentar la corriente para terminar antes","Confirmar su comodidad y seguir las precauciones aceptadas, consultando a su médico ante la duda","Negarse a hablar del tema","Tratar el abdomen de forma agresiva"],"re":"Muchos profesionales limitan o posponen el tratamiento durante el embarazo por precaución; verificar la comodidad y remitir al médico es el enfoque seguro."},
  {"id":45,"q":"En California, la licencia que permite usar una aguja o sonda para eliminar pelo con corriente eléctrica es la de:","opts":["Manicurista","Esteticista","Electrólogo","Barbero"],"re":"La licencia de electrólogo es la única del Consejo de Barbería y Cosmetología de California que permite a un licenciado usar una aguja o sonda para eliminar pelo."},
  {"id":46,"q":"Para optar al examen escrito de electrología de California, el solicitante debe completar:","opts":["Ninguna formación","Un curso requerido de horas de formación en una escuela aprobada","Solo un cuestionario en línea","Un título universitario de cuatro años"],"re":"California exige completar el curso establecido de horas de formación en electrología en una escuela aprobada antes de que un candidato pueda presentar el examen escrito."},
  {"id":47,"q":"Desde 2022, el examen de licencia de California para electrólogos consiste en:","opts":["Un examen escrito y un examen práctico","Solo una entrevista","Solo un examen práctico","Solo un examen escrito"],"re":"California eliminó la parte práctica en 2022, por lo que la licencia para electrólogos (y otras categorías) se basa solo en aprobar el examen escrito."},
  {"id":48,"q":"Se insiste en las sondas desechables de un solo uso principalmente para:","opts":["Prevenir la transmisión de enfermedades sanguíneas entre clientes","Ahorrar dinero al salón","Hacer las inserciones más rápidas","Cumplir con normas fiscales"],"re":"Como la sonda penetra la piel, usar una sonda estéril nueva con cada cliente es la principal salvaguarda contra la transmisión de patógenos sanguíneos."},
  {"id":49,"q":"Para ejercer legalmente la electrología en California, una persona debe:","opts":["Simplemente ser dueña del equipo","Tener solo una licencia de cosmetología","Tener una licencia de electrólogo vigente emitida por el Consejo","Trabajar sin ninguna licencia"],"re":"Ejercer la electrología por dinero requiere una licencia de electrólogo vigente del Consejo de Barbería y Cosmetología de California."},
  {"id":50,"q":"Los objetos punzantes y demás artículos contaminados con sangre deben tratarse como:","opts":["Basura doméstica común","Residuos médicos regulados en contenedores adecuados","Plástico reciclable","Abono (composta)"],"re":"Las sondas usadas y los artículos contaminados con sangre son residuos regulados (biopeligrosos) y deben colocarse en contenedores aprobados para punzantes o biopeligros."}
];
